    [t]
  );

  const setDefaults = useCallback(() => {
    const defaultConfiguration =
      configurationSelectorProps.configurations.find((opt) => opt.defaultForLeads) ||
      configurationSelectorProps.configurations[0];

    if (defaultConfiguration) {
      setValue('messageId', defaultConfiguration.id);
    } else {
      const isDonation = isDonationPage(getValues('pageType'));

      setValue(
        'messageConfiguration.body',
        isDonation
          ? t('actionMessages:form.defaults.donationBody')
          : t('actionMessages:form.defaults.leadBody')
      );

      setValue('messageConfiguration.contactDelayInMinutes', 30);
      setValue('messageConfiguration.defaultForLeads', false);
      setValue(
        'messageConfiguration.linkText',
        isDonation
          ? t('actionMessages:form.defaults.donationLinkText')
          : t('actionMessages:form.defaults.leadLinkText')
      );
      setValue('messageConfiguration.subject', t('actionMessages:form.defaults.subject'));
    }
  }, [getValues, setValue, t, configurationSelectorProps.configurations]);

  const toggleRecoveryEnabled = useCallback(() => {
    if (recoveryEnabled) {
      onCancel();
      setValue('recoveryEnabled', false);

      // @ts-ignore
      setValue('messageId', null);
      setValueRecursive({ getValues, prefix: 'messageConfiguration', setValue, values: {} });
    } else {
      setValue('recoveryEnabled', true);
      setDefaults();
    }
  }, [getValues, setValue, onCancel, setDefaults, recoveryEnabled]);

