  // Doing this via search param instead of just setting the value and defaults elsewhere and then switching
  //  pages because the defaults have to be set _after_ ConfigurationPanel is mounted in order for change
  //  tracking to realize a change and trigger editing mode with cancel/save buttons
  useEffect(() => {
