import { Box, Flex, VStack } from '@chakra-ui/layout';
import { TemplatePageType, TemplateQueryFilter } from '@domain/templates';
import { ChangeQueryFilter } from '@state/utils/useQueryFilters';
import { ChevronDownIcon } from '@ui/assets/icons/ChevronDownIcon';
import { FilterIcon } from '@ui/assets/icons/FilterIcon';
import { Button } from '@ui/components/Button';
import { CheckboxControl, CheckboxGroup } from '@ui/components/formControls/CheckboxControl';
import { SwitchControl } from '@ui/components/formControls/SwitchControl';
import { MotionAccordion } from '@ui/components/MotionAccordion';
import { Popover, PopoverBody, PopoverContent, PopoverTrigger } from '@ui/components/Popover';
import { Text } from '@ui/components/typography';
import { LayoutGroup } from 'framer-motion';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';

type FilterPopoverProps = {
  changeQueryFilter: ChangeQueryFilter<TemplateQueryFilter>;
  onApply: () => void;
  onClear: () => void;
  queryFilters: TemplateQueryFilter;
};

const getFilterCount = (filter: TemplateQueryFilter) => {
  if (!filter) {
    return 0;
  }

  let count = 0;

  if (filter.category) {
    count += filter.category.split(',').length;
  }

  if (filter.type) {
    count += filter.type.split(',').length;
  }

  if (filter.layout) {
    count += filter.layout.split(',').length;
  }

  return count;
};

export const FilterPopover = ({
  changeQueryFilter,
  onApply,
  onClear,
  queryFilters,
}: FilterPopoverProps) => {
  const { t } = useTranslation(['actionPagesBuilder', 'common']);
  const { isOpen, onClose, onOpen } = useDisclosure();
  const activeFilterCount = getFilterCount(queryFilters);

  const togglePopover = () => {
    if (isOpen) {
      onClose();
    } else {
      onOpen();
    }
  };

  const toggleOnlyFavorites = () => {
    if (queryFilters?.onlyFavorites === '1') {
      changeQueryFilter('onlyFavorites', undefined);
    } else {
      changeQueryFilter('onlyFavorites', '1');
    }
  };

  const items = useMemo(
    () => [
      {
        content: (
          <CheckboxGroup
            name="page_type"
            onChange={(types) => {
              if (types.length === 0) {
                changeQueryFilter('type', undefined);
              } else {
                changeQueryFilter('type', types.join(','));
              }
            }}
            value={queryFilters?.type?.split(',') ?? []}
            variant="checkbox"
          >
            <VStack alignItems="stretch" spacing={4} width="full">
              {Object.keys(TemplatePageType).map((type) => {
                const templatePageType: TemplatePageType = type as TemplatePageType;

                return (
                  <CheckboxControl key={type} value={templatePageType}>
                    {t(`actionPagesBuilder:template.types.${templatePageType}`)}
                  </CheckboxControl>
                );
              })}
            </VStack>
          </CheckboxGroup>
        ),
        id: 'page_type',
        title: t('actionPagesBuilder:pageType'),
      },
      {
        content: <Flex />, // TODO: fill out category list
        id: 'category',
        title: t('actionPagesBuilder:templateCategory'),
      },
      {
        content: <Flex />, // TODO: fill out layout type list
        id: 'layout_type',
        title: t('actionPagesBuilder:layoutType'),
      },
    ],
    [changeQueryFilter, queryFilters?.type, t]
  );

  return (
    <Popover closeOnBlur isOpen={isOpen} onClose={onClose} placement="bottom-start">
      <PopoverTrigger>
        <Box>
          <Button
            iconSpacing={2}
            isActive={isOpen || !!activeFilterCount}
            leftIcon={<FilterIcon />}
            onClick={togglePopover}
            rightIcon={
              <ChevronDownIcon
                transform={isOpen ? 'rotate(-180deg)' : ''}
                transition="transform .2s ease"
              />
            }
            variant="secondary"
          >
            <Text>{`${t('common:button.filter')}${
              activeFilterCount > 0 ? ` (${activeFilterCount})` : ''
            }`}</Text>
          </Button>
        </Box>
      </PopoverTrigger>
      <PopoverContent border="none" borderRadius="2xl" maxWidth="248px">
        <PopoverBody padding={4}>
          <LayoutGroup>
            <Flex flexDirection="column" position="relative" width="full">
              <MotionAccordion items={items} key="filter" />
              <Flex marginTop={4}>
                <SwitchControl
                  formControlProps={{ mb: 0 }}
                  formLabel={t('actionPagesBuilder:showOnlyFavorites')}
                  name="favorites"
                  onChange={toggleOnlyFavorites}
                  size="sm"
                  spaceBetween
                  value={queryFilters?.onlyFavorites === '1'}
                />
              </Flex>
              <Flex flexDirection="column" gap={2} justify="stretch" marginTop={4}>
                <Button onClick={onApply} variant="primary">
                  {t('common:button.applyFilters')}
                </Button>
                <Button onClick={onClear} variant="tertiary">
                  {t('common:button.clearFilters')}
                </Button>
              </Flex>
            </Flex>
          </LayoutGroup>
        </PopoverBody>
      </PopoverContent>
    </Popover>
  );
};

